canvas.init:
function init(canvas, params) {
  var ctx = canvas.getContext('2d');
  var W = canvas.width, H = canvas.height;
  var N = params.points || 150, R = params.radius || 60;
  var speedX = params.speedX || 0.005, speedY = params.speedY || 0.01;
  var color = getComputedStyle(canvas).getPropertyValue('--ct-text-strong').trim() || '#ffffff';
  var points = [];
  for (var i = 0; i < N; i++) {
    var phi = Math.acos(1 - 2 * (i + 0.5) / N);
    var theta = Math.PI * (1 + Math.sqrt(5)) * i;
    points.push({
      x: R * Math.cos(theta) * Math.sin(phi),
      y: R * Math.sin(theta) * Math.sin(phi),
      z: R * Math.cos(phi)
    });
  }
  var ax = 0, ay = 0;
  function draw() {
    ctx.clearRect(0, 0, W, H);
    ax += speedX; ay += speedY;
    var cx = Math.cos(ax), sx = Math.sin(ax);
    var cy = Math.cos(ay), sy = Math.sin(ay);
    var proj = points.map(function(p) {
      var x1 = p.x * cy - p.z * sy;
      var z1 = p.z * cy + p.x * sy;
      var y2 = p.y * cx - z1 * sx;
      var z2 = z1 * cx + p.y * sx;
      var s = 200 / (200 + z2);
      return { x: x1 * s + W / 2, y: y2 * s + H / 2, z: z2, s: s };
    });
    proj.sort(function(a, b) { return b.z - a.z; });
    proj.forEach(function(p) {
      var a = Math.max(0.1, 1 - (p.z + R) / (R * 2));
      ctx.beginPath();
      ctx.arc(p.x, p.y, 1.5 * p.s, 0, Math.PI * 2);
      ctx.globalAlpha = a;
      ctx.fillStyle = color;
      ctx.fill();
    });
    ctx.globalAlpha = 1;
    requestAnimationFrame(draw);
  }
  draw();
}
